import time, json, requests
from datetime import datetime, timezone

KV_LINKED_SERVICE   = "ls_kv"
APPINSIGHTS_SECRET  = "application-insights-connection-string"
HTTP_TIMEOUT_SECONDS = 15
MAX_RETRIES = 3
RETRY_BACKOFF_SECONDS = 2
DEFAULT_INGESTION_ENDPOINT = "https://uksouth-1.in.applicationinsights.azure.com/"

def _parse_connection_string(conn_str):
    parts = {}
    for seg in conn_str.split(";"):
        seg = seg.strip()
        if seg and "=" in seg:
            k, v = seg.split("=", 1)
            parts[k.strip()] = v.strip()
    return parts

def _get_appinsights_config():
    conn_str = mssparkutils.credentials.getSecretWithLS(KV_LINKED_SERVICE, APPINSIGHTS_SECRET)
    if not conn_str:
        raise ValueError("App Insights connection string secret is empty.")
    cfg = _parse_connection_string(conn_str)
    ikey = cfg.get("InstrumentationKey")
    if not ikey:
        if "=" not in conn_str and len(conn_str.strip()) >= 32:
            ikey = conn_str.strip()
        else:
            raise ValueError("Could not find InstrumentationKey in connection string.")
    endpoint = cfg.get("IngestionEndpoint", DEFAULT_INGESTION_ENDPOINT).rstrip("/")
    return ikey, endpoint + "/v2/track"

def _utc_now_iso():
    return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S.%f")[:-3] + "Z"

def send_telemetry_to_app_insights(params):
    result = {"ok": False, "status": None, "accepted": None, "error": None}
    try:
        ikey, track_url = _get_appinsights_config()
    except Exception as e:
        result["error"] = f"Config error: {e!r}"; print(result["error"]); return result

    print(f"App Insights target ikey prefix: {ikey[:8]} | endpoint: {track_url}")

    body = {
        "Stage": params.get("Stage"), "PipelineName": params.get("PipelineName"),
        "PipelineRunID": params.get("PipelineRunID"), "StartTime": params.get("StartTime"),
        "EndTime": params.get("EndTime"), "Inserts": str(params.get("Inserts", 0)),
        "Updates": str(params.get("Updates", 0)), "Deletes": str(params.get("Deletes", 0)),
        "ErrorMessage": params.get("ErrorMessage"), "StatusMessage": params.get("StatusMessage"),
        "PipelineTriggerID": params.get("PipelineTriggerID"),
        "PipelineTriggerName": params.get("PipelineTriggerName"),
        "PipelineTriggerType": params.get("PipelineTriggerType"),
        "PipelineTriggeredbyPipelineName": params.get("PipelineTriggeredbyPipelineName"),
        "PipelineTriggeredbyPipelineRunID": params.get("PipelineTriggeredbyPipelineRunID"),
        "PipelineExecutionTimeInSec": params.get("PipelineExecutionTimeInSec"),
        "ActivityType": params.get("ActivityType"), "StatusCode": params.get("StatusCode"),
        "DurationSeconds": params.get("DurationSeconds"),
    }
    payload = {
        "name": "Microsoft.ApplicationInsights.Event", "time": _utc_now_iso(), "iKey": ikey,
        "data": {"baseType": "EventData", "baseData": {
            "ver": 2, "name": params.get("AppInsCustomEventName", "ODW_Master_Pipeline_Logs"),
            "properties": {k: ("" if v is None else str(v)) for k, v in body.items()}}},
    }

    last_error = None
    for attempt in range(1, MAX_RETRIES + 1):
        try:
            resp = requests.post(track_url, json=payload, timeout=HTTP_TIMEOUT_SECONDS)
            result["status"] = resp.status_code
            accepted = None
            try: accepted = resp.json().get("itemsAccepted"); result["accepted"] = accepted
            except Exception: pass
            if resp.status_code == 200 and (accepted is None or accepted >= 1):
                print(f"Telemetry accepted: status=200 itemsAccepted={accepted}")
                result["ok"] = True; return result
            if resp.status_code == 200 and accepted == 0:
                last_error = f"itemsAccepted=0 (throttled/rejected). Body: {resp.text[:300]}"
                print("WARNING:", last_error)
            elif resp.status_code in (429, 500, 502, 503, 504):
                last_error = f"Transient {resp.status_code}. Body: {resp.text[:200]}"
                print("WARNING:", last_error)
            else:
                result["error"] = f"Non-retryable {resp.status_code}. Body: {resp.text[:300]}"
                print("ERROR:", result["error"]); return result
        except requests.exceptions.RequestException as e:
            last_error = f"{type(e).__name__}: {e}"
            print(f"WARNING: attempt {attempt} failed: {last_error}")
        if attempt < MAX_RETRIES:
            time.sleep(RETRY_BACKOFF_SECONDS * attempt)

    result["error"] = last_error or "send failed after retries"
    print(f"ERROR: telemetry failed after {MAX_RETRIES} attempts: {result['error']}")
    return result
